parameters.query:
WITH owner AS (
  SELECT c.owner_user_id FROM appdata.opportunities o JOIN appdata.clients c ON c.id = o.client_id WHERE o.id = $1::bigint
), task AS (
  INSERT INTO appdata.tasks (entity_type, entity_id, assignee_user_id, title, stage_ref)
  VALUES ('audit', $2::bigint, (SELECT owner_user_id FROM owner), 'AI nie zadziałało — napisz ręcznie rekomendację dla opportunity #' || $1::bigint, 'demo')
  RETURNING id
)
SELECT (SELECT id FROM task) AS task_id;
